import React, { useState } from 'react';
import { Send } from 'lucide-react';

const CareerMentor = () => {
  const [messages, setMessages] = useState([
    { role: 'assistant', content: 'Hello! I am your AI Career Mentor. I can help you with interview prep, career advice, and skill development. What would you like to discuss today?' }
  ]);
  const [input, setInput] = useState('');

  const handleSend = () => {
    if (!input.trim()) return;
    setMessages([...messages, { role: 'user', content: input }]);
    setInput('');
    // Placeholder for API call
  };

  return (
    <div className="animate-fade-in" style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
      <div style={{ marginBottom: '1rem' }}>
        <h1 style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>AI Career <span className="text-gradient">Mentor</span></h1>
        <p>Chat with your personalized guide for the tech industry.</p>
      </div>

      <div className="glass-panel" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div style={{ flex: 1, padding: '2rem', overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
          {messages.map((msg, idx) => (
            <div key={idx} style={{
              alignSelf: msg.role === 'user' ? 'flex-end' : 'flex-start',
              maxWidth: '80%',
              backgroundColor: msg.role === 'user' ? 'var(--accent-primary)' : 'rgba(255,255,255,0.05)',
              padding: '1rem',
              borderRadius: 'var(--border-radius)',
              borderBottomRightRadius: msg.role === 'user' ? 0 : 'var(--border-radius)',
              borderBottomLeftRadius: msg.role === 'assistant' ? 0 : 'var(--border-radius)',
            }}>
              <p style={{ color: '#fff', margin: 0, fontSize: '0.95rem' }}>{msg.content}</p>
            </div>
          ))}
        </div>

        <div style={{ padding: '1rem', borderTop: '1px solid var(--glass-border)', display: 'flex', gap: '1rem' }}>
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask about AI Engineering interviews..."
            style={{
              flex: 1,
              background: 'rgba(0,0,0,0.2)',
              border: '1px solid var(--glass-border)',
              borderRadius: '8px',
              padding: '0.8rem 1rem',
              color: '#fff',
              outline: 'none',
              fontSize: '1rem'
            }}
          />
          <button onClick={handleSend} className="btn btn-primary" style={{ padding: '0.8rem' }}>
            <Send size={20} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default CareerMentor;
